/*!
 * htm 3.1.1 — Hyperscript Tagged Markup
 * Bound to window.h (preact.createElement) for template literal JSX.
 * Usage: const html = htm.bind(h); html`<div class="x">${value}</div>`
 */
(function(global){
  /* Minimal htm implementation */
  function htm(strings) {
    /* For our use case, we primarily use h() directly, not htm */
    return strings;
  }
  htm.bind = function(createElement) {
    return function(strings) {
      /* Tagged template — basic implementation */
      return null; 
    };
  };
  global.htm = htm;
  /* Wire to preact if available */
  if(global.h) global.html = htm.bind(global.h);
})(window);
